<script setup>
//This file is generated by Table2API.
//If you met a bug, please tell me, thanks!
//wrx 202200905
import { onMounted, ref } from 'vue';
import PageFrame from '@common/layout/FrameIndi_Classic.vue';
import MainPage from '@common/MainPage.vue';
import Page404 from '@common/ResultPage/Page404.vue';

import GetMenu from './MenuData';

//此处引入页面组件
import dict_silo from './views/Dict_silo/component_new/dict_silo_Page.vue';
import rfa_resource from './views/Rfa_resource/component_new/rfa_resource_Page.vue';
import task_base from './views/Task_base/component_new/task_base_Page.vue';
import task_result from './views/Task_result/component_new/task_result_Page.vue';
import template_silo from './views/Template_silo/component_new/template_silo_Page.vue';

import {
    getMenuHome,
    executeMenuIcon,
    executeMenuLabel,
    killMenuChildren,
    searchMenuByKey,
} from '@common/layout/indexFuncModified';
import { useStore } from '/src/store/totalStore.js';
import { translate } from '@utility/i18n.js';

const store = useStore(); // 全局参数

const NAMESPACE = import.meta.env.VITE_NAMESPACE;

const PageFrameRef = ref(null);

let initMenuHome = getMenuHome(translate.t('首页'));

const keepAliveArray = ref([]); //用于删除Tab取消菜单的持久化
const menus = ref([]);
const menuKey = ref('Home');
const menuObj = ref(initMenuHome);

onMounted(() => {
    window.addEventListener('hashchange', () => {
        updateMenu(location.hash.substring(1));
        if (PageFrameRef.value) {
            PageFrameRef.value.DoMenuRefresh();
        }
    });

    menus.value = GetMenu();
    killMenuChildren(menus.value);

    updateMenu(location.hash.substring(1));
    if (PageFrameRef.value) {
        PageFrameRef.value.DoMenuRefresh();
    }
});

//点选菜单
function menuSelected(key) {
    updateMenu(key);
    window.location.hash = key;
}

//更新menuKey,menuObj
function updateMenu(key) {
    if (key == 'Home' || key == '') {
        menuKey.value = key;
        menuObj.value = initMenuHome;
    } else {
        let tempMenuObj = searchMenuByKey(menus.value, key);
        if (Object.keys(tempMenuObj).length > 0) {
            menuKey.value = key;
            menuObj.value = tempMenuObj;
        } else {
            menuKey.value = '404';
            menuObj.value = {};
        }
    }
}

//通过tab的方式关闭菜单
function menuKilled(key) {
    keepAliveArray.value.push(key);
    setTimeout(() => {
        keepAliveArray.value = [];
    }, 1000);
}

//渲染菜单文字
function renderMenuLabel(val) {
    return executeMenuLabel(translate.t(val.label));
}

//渲染菜单图标
function renderMenuIcon(val) {
    return executeMenuIcon(val);
}
</script>
<template>
    <PageFrame
        ref="PageFrameRef"
        :platformTitle="translate.t(NAMESPACE)"
        :menus="menus"
        :menuSelectObj="menuObj"
        @menuSelected="menuSelected"
        @menuTabKilled="menuKilled"
        :renderMenuIcon="renderMenuIcon"
        :renderMenuLabel="renderMenuLabel"
    >
        <template v-slot:main>
            <!-- keep-alive中不可以有注释，同一条件下只允许有一个dom节点 -->
            <keep-alive :exclude="keepAliveArray">
                <MainPage v-if="menuKey == 'Home' || menuKey == ''" :msg="'Welcome'"></MainPage>
                <dict_silo v-else-if="menuKey == 'dict_silo'"></dict_silo>
                <rfa_resource v-else-if="menuKey == 'rfa_resource'"></rfa_resource>
                <task_base v-else-if="menuKey == 'task_base'"></task_base>
                <task_result v-else-if="menuKey == 'task_result'"></task_result>
                <template_silo v-else-if="menuKey == 'template_silo'"></template_silo>
                <Page404 v-else></Page404>
            </keep-alive>
        </template>
    </PageFrame>
</template>
<style></style>
